import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";

const SideDrawer = () => {
  const [open, setOpen] = useState(false);
  const [profileImage, setProfileImage] = useState("");
  const navigate = useNavigate();
  const location = useLocation();

  // Check if user is logged in
  const token = localStorage.getItem("token");
  const userId = localStorage.getItem("userId");
  const isLoggedIn = !!token && !!userId;

  // Load profile image only if user is logged in
  useEffect(() => {
    if (isLoggedIn && userId) {
      const data = JSON.parse(localStorage.getItem(`profile_${userId}`)) || {};
      setProfileImage(data.image || "");
    }
  }, [isLoggedIn, userId]);

  // Don't show on profile page or auth pages
  const isProfilePage = location.pathname === "/dashboard/profile";
  const isAuthPage = ["/", "/login", "/register", "/otp-verify", "/forgot-password", "/reset-password"].includes(location.pathname);

  // If on auth page or not logged in, don't render
  if (isAuthPage || !isLoggedIn) {
    return null;
  }

  const handleNavigation = (path) => {
    navigate(path);
    setOpen(false);
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("userId");
    localStorage.removeItem("user");
    navigate("/login");
    setOpen(false);
  };

  return (
    <>
      {/* ☰ Menu Button - Hide on profile page */}
      {!isProfilePage && (
        <button
          onClick={() => setOpen(!open)}
          style={{
            position: "fixed",
            top: "20px",
            left: "20px",
            zIndex: 1000,
            fontSize: "22px",
            background: "#333",
            color: "#fff",
            border: "none",
            padding: "10px 15px",
            borderRadius: "5px",
            cursor: "pointer",
            transition: "all 0.3s",
          }}
          onMouseEnter={(e) => e.target.style.background = "#555"}
          onMouseLeave={(e) => e.target.style.background = "#333"}
        >
          ☰
        </button>
      )}

      {/* Top Right Profile Button - Hide on profile page */}
      {!isProfilePage && (
        <div
          onClick={() => handleNavigation("/dashboard/profile")}
          style={{
            position: "fixed",
            top: "20px",
            right: "20px",
            zIndex: 1000,
            cursor: "pointer",
          }}
        >
          <img
            src={profileImage || "https://via.placeholder.com/50"}
            alt="Profile"
            style={{
              width: "50px",
              height: "50px",
              borderRadius: "50%",
              objectFit: "cover",
              border: "2px solid #ff6b6b",
              transition: "transform 0.3s",
            }}
            onMouseEnter={(e) => e.target.style.transform = "scale(1.05)"}
            onMouseLeave={(e) => e.target.style.transform = "scale(1)"}
          />
        </div>
      )}

      {/* Sidebar */}
      <div
        style={{
          position: "fixed",
          top: 0,
          left: open ? "0" : "-280px",
          width: "280px",
          height: "100%",
          background: "linear-gradient(180deg, #1a1a2e 0%, #16213e 100%)",
          color: "#fff",
          paddingTop: "80px",
          transition: "0.3s ease-in-out",
          zIndex: 999,
          boxShadow: "2px 0 10px rgba(0,0,0,0.3)",
        }}
      >
        {/* User Info Section */}
        <div style={{
          textAlign: "center",
          padding: "0 20px 20px",
          borderBottom: "1px solid rgba(255,255,255,0.1)",
          marginBottom: "20px"
        }}>
          <img
            src={profileImage || "https://via.placeholder.com/80"}
            alt="User"
            style={{
              width: "80px",
              height: "80px",
              borderRadius: "50%",
              marginBottom: "10px",
              border: "3px solid #ff6b6b"
            }}
          />
          <div style={{ fontWeight: "bold", fontSize: "18px" }}>
            {JSON.parse(localStorage.getItem("user") || "{}").name || "User"}
          </div>
        </div>

        <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
          <li 
            style={itemStyle} 
            onClick={() => handleNavigation("/dashboard")}
          >
            📊 Dashboard
          </li>
          <li 
            style={itemStyle} 
            onClick={() => handleNavigation("/dashboard/profit")}
          >
            📈 Profit
          </li>
          <li 
            style={itemStyle} 
            onClick={() => handleNavigation("/dashboard/loss")}
          >
            📉 Loss
          </li>
          <li 
            style={itemStyle} 
            onClick={() => handleNavigation("/dashboard/expense")}
          >
            💰 Expense
          </li>
          <li 
            style={itemStyle} 
            onClick={() => handleNavigation("/dashboard/analytics")}
          >
            📊 Analytics
          </li>
          <li 
            style={itemStyle} 
            onClick={() => handleNavigation("/dashboard/profile")}
          >
            👤 My Profile
          </li>
          <li 
            style={{...itemStyle, borderTop: "1px solid rgba(255,255,255,0.1)", marginTop: "20px", color: "#ff6b6b"}} 
            onClick={handleLogout}
          >
            🚪 Logout
          </li>
        </ul>
      </div>

      {/* Overlay when sidebar is open */}
      {open && (
        <div
          onClick={() => setOpen(false)}
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: "rgba(0,0,0,0.5)",
            zIndex: 998,
          }}
        />
      )}
    </>
  );
};

const itemStyle = {
  padding: "15px 25px",
  cursor: "pointer",
  borderBottom: "1px solid rgba(255,255,255,0.05)",
  transition: "all 0.3s",
  fontSize: "16px",
  display: "flex",
  alignItems: "center",
  gap: "10px",
};

export default SideDrawer;
